module top_module(
                                  datain,
                                  addnsub,
                                  operation,
                                  dataout
                                 );//PARAMETERS
parameter  operation_mode = "dynamic";

//INPUT PORTS
input [143:0] datain;
input [3:0]    operation;
input          addnsub;

//OUTPUT PORTS
output [143:0] dataout;

//INTERNAL SIGNALS
reg [143:0] datain_filtered;

always @ (datain, addnsub, operation_mode, operation)
begin
    if(operation_mode == "dynamic")
    begin
        case (operation)
            4'b1100 : // TWO ACCUMULATORS
                datain_filtered = {18'bX, datain[124:108],1'bX, datain[107:72],18'bX, datain[52:36], 1'bX, datain[35:0]};
            4'b1101 : // OUTPUT ONLY / ACCUMULATOR
                datain_filtered = {datain[143:72], 18'bX, datain[52:36], 1'bX, datain[35:0]};
            4'b1110 :// ACCUMULATOR / OUTPUT ONLY
                datain_filtered = {18'bX, datain[124:108], 1'bX, datain[107:0]};
            4'b0111 :
                begin // 36 BIT MULTIPLY
                    datain_filtered[17:0] = (addnsub) ? datain[17:0] : 18'bX;
                    datain_filtered[35:18] = (addnsub) ? datain[53:36] : 18'bX;
                    datain_filtered[53:36] = (addnsub) ? datain[35:18] : 18'bX;
                    datain_filtered[71:54] = (addnsub) ? datain[71:54] : 18'bX;
                    datain_filtered[143:72] = 72'bX;
                end
            default :
                 datain_filtered = datain;
        endcase
    end
    else
        datain_filtered = datain;
end

assign dataout = datain_filtered;

endmodule
